class TestAnalyzeAdoc:
    """Tests for structural analysis of .adoc files."""

    def test_extracts_title(self, tmp_path):
        f = write_adoc(tmp_path, "test.adoc", "= My Guide Title\n\nSome content.\n")
        result = analyze_adoc(f)
        assert result["title"] == "My Guide Title"

    def test_extracts_diataxis_type(self, tmp_path):
        content = "= Title\n:diataxis-type: howto\n\nContent here.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["diataxis_type"] == "howto"

    def test_diataxis_type_case_insensitive(self, tmp_path):
        content = "= Title\n:diataxis-type: Tutorial\n\nContent.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["diataxis_type"] == "tutorial"

    def test_no_diataxis_type(self, tmp_path):
        content = "= Title\n\nContent here.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["diataxis_type"] == ""

    def test_diataxis_type_only_from_header(self, tmp_path):
        """Ensure :diataxis-type: in body text (after first blank line) is NOT captured."""
        content = (
            "= Title\n\n"  # blank line ends header
            "Some content.\n\n"
            ":diataxis-type: howto\n"  # this is in the body, not header
        )
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["diataxis_type"] == ""

    def test_counts_code_blocks(self, tmp_path):
        content = "= Title\n\n[source,java]\n----\ncode\n----\n\n[source,xml]\n----\nmore\n----\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["code_block_count"] == 2

    def test_counts_sections(self, tmp_path):
        content = "= Title\n\n== Section 1\n\nText.\n\n== Section 2\n\nText.\n\n=== Subsection\n\nText.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["section_count"] == 2  # only level-2 sections

    def test_detects_tutorial_signals(self, tmp_path):
        content = (
            "= Getting Started\n\n"
            "== Prerequisites\n\nJava 17.\n\n"
            "== Creating the Maven project\n\nText.\n\n"
            "include::{includes}/devtools/create-app.adoc[]\n\n"
            "== Running the application\n\nText.\n"
        )
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert len(result["tutorial_signals"]) >= 3
        assert result["devtools_includes"] == 1

    def test_detects_reference_signals(self, tmp_path):
        content = (
            "= Config Reference\n\n"
            "== Configuration Reference\n\n"
            "include::{generated-dir}/config/quarkus-foo.adoc[]\n\n"
            "[cols=\"80,10,10\"]\n|===\n| col1 | col2\n|===\n"
        )
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert len(result["reference_signals"]) >= 2
        assert result["config_table_count"] >= 1

    def test_detects_procedure_heading(self, tmp_path):
        content = "= Configure X\n\n== Procedure\n\n. Do step 1.\n. Do step 2.\n. Do step 3.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["has_procedure_heading"] is True
        assert result["ordered_step_count"] >= 3

    def test_detects_concept_headings(self, tmp_path):
        content = (
            "= Security architecture\n\n"
            "== Overview\n\nText.\n\n"
            "== How authentication works\n\nMore text.\n"
        )
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["concept_heading_count"] >= 2

    def test_detects_diagrams(self, tmp_path):
        content = "= Architecture\n\nimage::arch-diagram.png[Architecture]\n\nText.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["diagram_count"] == 1

    def test_captures_prose_sample(self, tmp_path):
        content = "= Title\n:some-attr: value\n\nThis is the first real paragraph of content.\n"
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["prose_sample"] == "This is the first real paragraph of content."

    def test_file_not_found(self, tmp_path):
        result = analyze_adoc(tmp_path / "nonexistent.adoc")
        assert "error" in result

    def test_imperative_sentences_not_counted_in_code(self, tmp_path):
        content = (
            "= Title\n\n"
            "Create a file.\n\n"  # counted
            "[source,java]\n----\n"
            "Create something;\n"  # NOT counted (in code block)
            "----\n"
        )
        f = write_adoc(tmp_path, "test.adoc", content)
        result = analyze_adoc(f)
        assert result["imperative_sentence_count"] == 1


