class TestClassify:
    """Tests for the classification logic."""

    def _base_analysis(self, **overrides) -> dict:
        """Create a minimal analysis dict with sensible defaults."""
        base = {
            "title": "Some Guide",
            "diataxis_type": "",
            "total_lines": 300,
            "section_count": 5,
            "sections": [],
            "code_block_count": 5,
            "tutorial_signals": [],
            "reference_signals": [],
            "howto_signals": [],
            "config_table_count": 0,
            "generated_config_includes": [],
            "devtools_includes": 0,
            "ordered_step_count": 0,
            "imperative_sentence_count": 0,
            "has_procedure_heading": False,
            "concept_heading_count": 0,
            "explanatory_sentence_count": 0,
            "diagram_count": 0,
            "xref_count": 0,
            "prose_sample": "",
            "filename": "some-guide.adoc",
        }
        base.update(overrides)
        return base

    def test_metadata_takes_precedence(self):
        analysis = self._base_analysis(
            diataxis_type="howto",
            tutorial_signals=[(10, "heading"), (20, "heading"), (30, "heading")],
        )
        result = classify(analysis)
        assert result["suggested_type"] == "howto"
        assert result["confidence"] == "high"
        assert result["source"] == "metadata"

    def test_metadata_tutorial(self):
        analysis = self._base_analysis(diataxis_type="tutorial")
        result = classify(analysis)
        assert result["suggested_type"] == "tutorial"
        assert result["source"] == "metadata"

    def test_metadata_concept(self):
        analysis = self._base_analysis(diataxis_type="concept")
        result = classify(analysis)
        assert result["suggested_type"] == "concept"
        assert result["source"] == "metadata"

    def test_metadata_reference(self):
        analysis = self._base_analysis(diataxis_type="reference")
        result = classify(analysis)
        assert result["suggested_type"] == "reference"
        assert result["source"] == "metadata"

    def test_invalid_metadata_falls_through(self):
        analysis = self._base_analysis(diataxis_type="core")
        result = classify(analysis)
        assert result["source"] == "heuristic"  # not metadata

    def test_tutorial_from_signals(self):
        analysis = self._base_analysis(
            tutorial_signals=[
                (10, "heading: Prerequisites"),
                (20, "heading: Creating the Maven project"),
                (30, "heading: Running the application"),
            ],
            devtools_includes=1,
        )
        result = classify(analysis)
        assert result["suggested_type"] == "tutorial"
        assert result["confidence"] in ("high", "medium")

    def test_reference_from_title(self):
        analysis = self._base_analysis(
            title="Configuration Reference",
            generated_config_includes=[100, 200],
            config_table_count=5,
        )
        result = classify(analysis)
        assert result["suggested_type"] == "reference"

    def test_howto_from_procedure_heading(self):
        analysis = self._base_analysis(
            has_procedure_heading=True,
            ordered_step_count=5,
            imperative_sentence_count=8,
        )
        result = classify(analysis)
        assert result["suggested_type"] == "howto"

    def test_howto_from_filename_suffix(self):
        analysis = self._base_analysis(
            filename="security-oidc-howto.adoc",
            ordered_step_count=3,
        )
        result = classify(analysis)
        assert result["suggested_type"] == "howto"
        assert result["source"] == "heuristic"

    def test_concept_from_title_and_headings(self):
        analysis = self._base_analysis(
            title="Quarkus Security architecture",
            concept_heading_count=3,
            explanatory_sentence_count=10,
            code_block_count=1,
            total_lines=150,
        )
        result = classify(analysis)
        assert result["suggested_type"] == "concept"

    def test_mixed_tutorial_reference(self):
        analysis = self._base_analysis(
            tutorial_signals=[
                (10, "heading"), (20, "heading"), (30, "heading"),
            ],
            devtools_includes=1,
            reference_signals=[
                (200, "heading"), (300, "generated config"),
            ],
            generated_config_includes=[300],
            config_table_count=4,
        )
        result = classify(analysis)
        assert result["suggested_type"].startswith("mixed:")
        assert "tutorial" in result["suggested_type"]
        assert "reference" in result["suggested_type"]

    def test_error_analysis(self):
        result = classify({"error": "File not found"})
        assert result["suggested_type"] == "unknown"
        assert result["confidence"] == "none"

    def test_unclassified_guide(self):
        analysis = self._base_analysis(
            total_lines=50,
            code_block_count=1,
            section_count=1,
        )
        result = classify(analysis)
        # With minimal signals, concept gets score=1 (moderate size) which is
        # below SCORE_THRESHOLD=2, so it falls through to unclassified "guide"
        assert result["suggested_type"] == "guide"
        assert result["confidence"] == "none"
        assert result["source"] == "heuristic"


