class TestMergeClassification:
    """Tests for merging heuristic and LLM classifications."""

    def test_high_confidence_heuristic_wins(self):
        heuristic = {
            "suggested_type": "tutorial",
            "confidence": "high",
            "reason": "3 tutorial signals",
            "source": "heuristic",
        }
        llm = {"type": "howto", "confidence": "high", "reason": "LLM says howto"}
        result = merge_classification(heuristic, llm)
        assert result["suggested_type"] == "tutorial"
        assert result["llm_agrees"] is False

    def test_agreement_boosts_confidence(self):
        heuristic = {
            "suggested_type": "howto",
            "confidence": "medium",
            "reason": "procedure heading",
            "source": "heuristic",
        }
        llm = {"type": "howto", "confidence": "high", "reason": "task-oriented"}
        result = merge_classification(heuristic, llm)
        assert result["suggested_type"] == "howto"
        assert result["confidence"] == "high"
        assert result["llm_agrees"] is True

    def test_low_heuristic_defers_to_llm(self):
        heuristic = {
            "suggested_type": "guide",
            "confidence": "none",
            "reason": "no signals",
            "source": "heuristic",
        }
        llm = {"type": "concept", "confidence": "high", "reason": "explanatory content"}
        result = merge_classification(heuristic, llm)
        assert result["suggested_type"] == "concept"
        assert result["confidence"] == "medium"  # capped
        assert result["source"] == "llm"

    def test_medium_disagreement_reports_both(self):
        heuristic = {
            "suggested_type": "howto",
            "confidence": "medium",
            "reason": "some signals",
            "source": "heuristic",
        }
        llm = {"type": "tutorial", "confidence": "medium", "reason": "learning-oriented"}
        result = merge_classification(heuristic, llm)
        assert result["suggested_type"] == "howto"  # heuristic kept
        assert result["llm_agrees"] is False
        assert result["llm_type"] == "tutorial"
